// Extract the message content and metadata
const message = $input.first().json;

const messageBody = message.body?.content || message.body?.text || '';
const messageId = message.id || '';
const channelId = message.channelIdentity?.channelId || '';
const teamId = message.channelIdentity?.teamId || '';
const sender = message.from?.user?.displayName || 'Unknown';

// Filter out bot replies to prevent loops (skip messages from apps/bots)
const fromType = message.from?.application ? 'application' : (message.from?.device ? 'device' : 'user');
if (fromType !== 'user') {
  return [];
}

// Skip empty messages
if (!messageBody || messageBody.trim().length === 0) {
  return [];
}

// Strip HTML tags from message body if present
const cleanMessage = messageBody.replace(/<[^>]*>/g, '').trim();

return [{
  json: {
    question: cleanMessage,
    messageId: messageId,
    channelId: channelId,
    teamId: teamId,
    sender: sender,
    timestamp: new Date().toISOString()
  }
}];

// Aggregate all research results from the 3 parallel agents
const question = $('Extract & Validate Message').first().json.question;
const sender = $('Extract & Validate Message').first().json.sender;
const channelId = $('Extract & Validate Message').first().json.channelId;
const teamId = $('Extract & Validate Message').first().json.teamId;
const messageId = $('Extract & Validate Message').first().json.messageId;

// Collect outputs from each research agent
const webSearchResult = $('Web Search Agent').first()?.json?.output || 'No result from web search agent.';
const wikipediaResult = $('Wikipedia Research Agent').first()?.json?.output || 'No result from Wikipedia agent.';
const deepResearchResult = $('Deep Research Agent').first()?.json?.output || 'No result from deep research agent.';

return [{
  json: {
    question: question,
    sender: sender,
    channelId: channelId,
    teamId: teamId,
    messageId: messageId,
    researchResults: {
      webSearch: webSearchResult,
      wikipedia: wikipediaResult,
      deepResearch: deepResearchResult
    },
    aggregatedPrompt: `You are an expert answer synthesizer. Three research agents have independently investigated the following question asked by ${sender} in the HELP channel:

**QUESTION:**
${question}

---

**RESEARCH AGENT 1 - Web Search Results:**
${webSearchResult}

---

**RESEARCH AGENT 2 - Wikipedia / Encyclopedic Research:**
${wikipediaResult}

---

**RESEARCH AGENT 3 - Deep Research / Technical Documentation:**
${deepResearchResult}

---

Please synthesize all of this research into ONE comprehensive, clear, and accurate final answer. Your answer should:
1. Directly address the question
2. Combine the best insights from all three research sources
3. Resolve any contradictions between sources (prefer the most authoritative/recent source)
4. Be well-structured with clear sections if the answer is complex
5. Include relevant links or references if available from the research
6. Be written in a helpful, professional tone suitable for a Teams channel response
7. Start with a direct answer, then provide supporting details

Format the answer in Markdown for readability in Teams.`
  }
}];

// Format the final Teams message
const synthesizedAnswer = $('Answer Synthesizer Agent').first().json.output || 'I was unable to find a satisfactory answer to your question.';
const question = $('Aggregate Research Results').first().json.question;
const sender = $('Aggregate Research Results').first().json.sender;
const teamId = $('Aggregate Research Results').first().json.teamId;
const channelId = $('Aggregate Research Results').first().json.channelId;

const finalMessage = `**Research Answer for @${sender}**\n\n> **Question:** ${question}\n\n---\n\n${synthesizedAnswer}\n\n---\n*This answer was researched by 3 AI agents (Web Search, Wikipedia, Deep Research) and synthesized into this response.*`;

return [{
  json: {
    teamId: teamId,
    channelId: channelId,
    message: finalMessage
  }
}];
